INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00412', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民身分法之規定，下列敘述何者錯誤？', '["所謂山地原住民，係指臺灣光復前原籍在山地行政區域內，且戶口調查簿登記其本人或直系血親尊 親屬屬於原住民者", "所謂平地原住民，係指臺灣光復前原籍在平地行政區域內，且戶口調查簿登記其本人或直系血親尊 親屬屬於原住民，並申請戶籍所在地鄉（鎮、市、區）公所登記為平地原住民有案者", "山地原住民與平地原住民身分，任何情形都不可互換", "原住民身分，依法可以拋棄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00413', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據財團法人原住民族語言研究發展基金會設置條例之規定，本基金會之工作人員，除會計相關人員 外，應具備那一種程度以上的原住民族語言能力認證？', '["初級", "中級", "中高級", "高級"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00414', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民保留地開發管理辦法，關於原住民申請無償取得原住民保留地所有權土地面積最高限額的 規定，以下敘述何者錯誤？', '["依區域計畫法編定為農牧用地、養殖用地或依都市計畫法劃定為農業區、保護區，並供農作、養殖 或畜牧使用之土地，每人一公頃", "依區域計畫法編定為林業用地或依都市計畫法劃定為保護區並供作造林使用之土地，每人一公頃", "依區域計畫法編定為林業用地或依都市計畫法劃定為保護區並供作造林使用之土地，每人一點五公頃", "依法得為建築使用之土地，每戶零點一公頃"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00415', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民保留地開發管理辦法第17條，原住民得申請無償取得原住民保留地所有權的資格條件裡， 下列那一項不屬之？', '["原住民依法於原住民保留地設定耕作權、地上權或農育權", "原住民於原住民保留地內有原有自住房屋", "原住民於本辦法施行前使用迄今之原住民保留地", "原住民取得耕作權或地上權登記後繼續自用滿五年者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00416', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族教育法之規定，中央政府應寬列預算，專款辦理原住民族教育，其比率應為何？', '["不得少於中央統籌分配款預算總額百分之一點九", "不得少於中央教育主管機關預算總額百分之一點九", "不得少於中央原住民族主管機關預算總額百分之一點九", "不得少於中央普通統籌分配款預算總額百分之一點九"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00417', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民學生升學保障及原住民公費留學辦法規定，原住民學生參加高級中等以上學校新生入學， 依其採計成績加總分百分之十計算，但取得原住民文化及語言能力證明者，以加總分百分之三十五計 算，此規定不適用於以下何者之新生入學？', '["高級中等學校、專科學校五年制", "技術校院四年制、二年制或專科學校二年制", "大學", "研究所"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00418', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族基本法之規定，政府或私人於某些土地上從事土地開發、資源利用、生態保育及學術研 究，應諮商並取得原住民族或部落同意或參與，原住民得分享相關利益。以下那一種類土地不屬之？', '["原住民傳統領域土地", "原住民保留地", "部落及其周邊一定範圍內之公有土地", "部落及其周邊一定範圍內之私有土地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00419', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據姓名條例的規定，關於原住民之姓氏，以下敘述何者有誤？', '["原住民之姓名登記，依其文化慣俗為之；其已依漢人姓名登記者，得申請回復其傳統姓名；回復傳 統姓名者，得申請回復原有漢人姓名", "原住民申請回復其傳統姓名或申請回復原有漢人姓名，無次數之限制", "原住民之傳統姓名或漢人姓名，均得以傳統姓名之羅馬拼音並列登記", "原住民因改漢姓造成家族姓氏誤植得申請改姓"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00420', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據森林法規定，原住民可以在原住民族傳統領域土地內的國有林或公有林依其生活慣俗需要採取森 林產物，以下何者非屬原住民族依生活慣俗採取森林產物規則內所列的生活慣俗？', '["有關農、林、漁、牧生產活動，傳統社會制度運作及傳統宗教信仰之祭祀禮儀行為", "有關出生禮、命名禮、成年禮、婚禮、喪禮及其他因各生命階段變動而舉行之禮俗行為", "有關日常生活中食、衣、住、行、育、樂、醫藥等行為", "有關日常生活中之買賣行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00421', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據行政院組織法與中央行政機關組織基準法相關規定，原住民族委員會屬於何種行政組織？', '["中央一級行政機關", "中央一級內部單位", "中央二級行政機關", "中央二級內部單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
